    let global_rc = Rc::new(RefCell::new(global));

    // C: L->tt = LUA_VTHREAD; — encoded by LuaValue::Thread enum variant
    // C: L->marked = luaC_white(g);
    // macros.tsv: luaC_white → g.current_white()
